import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { getFeatured, getCategories } from '../services/api';
import ProductCard from '../components/ProductCard';

const Home = () => {
  const [featured, setFeatured] = useState([]);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const load = async () => {
      try {
        const [f, c] = await Promise.all([getFeatured(), getCategories()]);
        setFeatured(f.data || []);
        setCategories(c.data || []);
      } catch (e) { console.error(e); }
      finally { setLoading(false); }
    };
    load();
  }, []);

  // Theme Variables to match your CSS
  const colors = {
    navy: '#4a5d53',
    gold: '#c2b2a3',
    cream: '#e2e4e1',
    white: '#ffffff',
    text: '#2d3632',
    gray: '#8b9691'
  };

  return (
    <div className="home" style={{ background: colors.cream }}>
      {/* Hero Section - Matches the "Designer's Collection" layout */}
      <section className="hero" style={{
        background: colors.navy,
        padding: '100px 5%',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        minHeight: '600px',
        position: 'relative',
        color: 'white'
      }}>
        <div className="hero-content" style={{ maxWidth: '600px', textAlign: 'left', zIndex: 2 }}>
          <p style={{ 
            color: colors.gold, 
            textTransform: 'uppercase', 
            letterSpacing: '4px', 
            fontSize: '13px', 
            marginBottom: '20px' 
          }}>Sustainable Furniture</p>

          <h1 style={{ 
            fontFamily: "'Cormorant Garamond', serif", 
            fontSize: 'clamp(40px, 6vw, 72px)', 
            lineHeight: '1.1', 
            marginBottom: '24px',
            fontWeight: '600'
          }}>
            Designer’s <br />
            <span style={{ color: colors.gold }}>Collection</span>
          </h1>

          <p style={{ 
            fontSize: '16px', 
            color: 'rgba(255,255,255,0.7)', 
            marginBottom: '40px',
            maxWidth: '450px'
          }}>
            Experience the harmony of sustainable materials and modern aesthetics in our latest 2026 furniture line.
          </p>

          <div className="hero-btns" style={{ display: 'flex', gap: '15px' }}>
            <Link to="/products" className="btn-primary" style={{
              background: colors.gold,
              color: colors.navy,
              padding: '14px 36px',
              fontWeight: '600',
              textDecoration: 'none',
              borderRadius: '2px', // Matching the sharp radius
              transition: 'var(--transition)'
            }}>Shop Now</Link>
          </div>
        </div>

        {/* Hero Image Mockup (Floating Right) */}
        <div style={{
          flex: '1',
          maxWidth: '500px',
          display: 'flex',
          justifyContent: 'center',
          zIndex: 1
        }} className="hero-img-container">
           <img 
            src="https://images.unsplash.com/photo-1586023492125-27b2c045efd7?w=800" 
            alt="Hero Chair"
            style={{ width: '100%', borderRadius: '4px', boxShadow: 'var(--shadow-lg)' }}
           />
        </div>
      </section>

      {/* Categories - Grid style like the template cards */}
      <section style={{ padding: '80px 5%', maxWidth: '1300px', margin: '0 auto' }}>
        <div style={{ marginBottom: '40px', textAlign: 'center' }}>
          <h2 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: '36px', color: colors.navy }}>
            Shop by Category
          </h2>
          <div style={{ width: '40px', hieght: '2px', background: colors.gold, margin: '15px auto' }}></div>
        </div>

        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
          gap: '20px'
        }}>
          {['Living', 'Bedroom', 'Dining', 'Office'].map(cat => (
            <Link key={cat} to={`/products?category=${cat}`} style={{
              background: colors.white,
              padding: '30px',
              textAlign: 'center',
              textDecoration: 'none',
              color: colors.navy,
              border: `1px solid ${colors.gray}33`,
              transition: 'all 0.3s ease'
            }}
            onMouseEnter={e => e.currentTarget.style.borderColor = colors.gold}
            onMouseLeave={e => e.currentTarget.style.borderColor = 'transparent'}
            >
              <h3 style={{ fontSize: '18px', fontWeight: '500' }}>{cat}</h3>
              <p style={{ fontSize: '12px', color: colors.gray, marginTop: '5px' }}>Explore Collection</p>
            </Link>
          ))}
        </div>
      </section>

      {/* Featured Products */}
      <section style={{ padding: '80px 5%', maxWidth: '1300px', margin: '0 auto' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '40px' }}>
          <h2 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: '32px', color: colors.navy }}>Featured Pieces</h2>
          <Link to="/products" style={{ color: colors.navy, fontSize: '14px', textDecoration: 'underline' }}>View All</Link>
        </div>

        {loading ? (
          <div style={{ textAlign: 'center', padding: '100px', color: colors.gray }}>Loading...</div>
        ) : (
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
            gap: '30px'
          }}>
            {featured.map(p => <ProductCard key={p._id} product={p} />)}
          </div>
        )}
      </section>

      {/* Simple Footer-style Promo */}
      <section style={{ background: colors.navy, padding: '80px 20px', textAlign: 'center', color: 'white' }}>
        <h2 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: '40px', marginBottom: '20px' }}>Join the SAS Aesthetic</h2>
        <p style={{ color: 'rgba(255,255,255,0.6)', marginBottom: '30px' }}>Subscribe for early access to the 2026 Collection.</p>
        <div style={{ display: 'flex', justifyContent: 'center', gap: '10px' }}>
            <input 
                placeholder="Email address" 
                style={{ width: '300px', background: 'rgba(255,255,255,0.1)', border: 'none', color: 'white', borderRadius: '2px' }} 
            />
            <button style={{ background: colors.gold, color: colors.navy, padding: '0 30px', fontWeight: '600', borderRadius: '2px' }}>Join</button>
        </div>
      </section>

      <style>{`
        @media (max-width: 768px) {
          .hero { flex-direction: column; text-align: center; padding-top: 60px; }
          .hero-content { margin-bottom: 40px; }
          .hero-img-container { display: none; }
        }
      `}</style>
    </div>
  );
};

export default Home;
